import './ExpansionPanelTitle.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { isValidElement, useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import { IconButton } from '../../IconButton';
import { Typography } from '../../Typography';
import type { ExpansionPanelTitleProps } from './ExpansionPanelTitle.types';

export const ExpansionPanelTitle: FC<ExpansionPanelTitleProps> = ({
	open = false,
	title,
	subTitle,
	description,
	iconName = Icons.NavArrowDown,
	customButton,
	className,
	...props
}) => {
	const titleTag = useMemo(() => {
		if (typeof title === 'string') {
			return (
				<Typography variant="subtitle1" className="dsb_title-text">
					{title}
				</Typography>
			);
		}

		return <>{title}</>;
	}, [title]);

	const subTitleTag = useMemo(
		() =>
			isValidElement(subTitle) ? (
				subTitle
			) : (
				<Typography variant="body3" className="dsb_subtitle-text">
					{subTitle}
				</Typography>
			),
		[subTitle],
	);

	const descriptionTag = useMemo(
		() =>
			isValidElement(description) ? (
				description
			) : (
				<Typography variant="body3" className="dsb_description-text">
					{description}
				</Typography>
			),
		[description],
	);

	return (
		<div data-testid="ExpansionPanelTitle" className={classNames('dsb_expansion-panel-title', className)} {...props}>
			<div className="dsb_title-left-part">
				{title && titleTag}
				{subTitle && subTitleTag}
			</div>
			{description && <div className="dsb_title-right-part">{descriptionTag}</div>}
			<div className="dsb_title-button-part">
				{customButton || (
					<IconButton
						aria-expanded
						size="large"
						iconName={iconName}
						className={classNames('dsb_expansion-icon-button', open && 'dsb_expansion-icon-button__rotated')}
					/>
				)}
			</div>
		</div>
	);
};
